sc_cat_item_producer.script:
// GlideRecord to query the sys_choice table to get the actual display names of the select box variables
function getDispayChoice(selectBoxChoice) {
    var gr = new GlideRecord('question_choice');
    gr.addQuery('value', selectBoxChoice);
    gr.query();
    if (gr.next()) {
        var displayName = gr.text;
        return displayName;
    } else {
        gs.info('No choice found for the selected value.');
    }
}

// Get the choice variable values
var choiceError = getDispayChoice(producer.error_check);
var choiceAttempts = getDispayChoice(producer.several_attempts);
var choiceDispay = getDispayChoice(producer.indicating_no_power);
var choiceInput = getDispayChoice(producer.user_inputs);

// Create dynamic description
var chechCharging = 'Is the charger fails to initiate or establish a connection with the vehicle?   ' +
    (producer.check_connection || 'N/A') + '\n';
var checkError = 'Is the display shows an error code or a “No Charging” message?   ' +
    (choiceError || 'N/A') + '\n';
var checkAttempts = 'Is the charging cannot start or continues to fail after several attempts?   ' +
    (choiceAttempts || 'N/A') + '\n';
var checkDispay = 'Is the charging LED indicator light is either blinking continuously or stays off, indicating no power or charging activity?   ' +
    (choiceDispay || 'N/A') + '\n';
var checkInput = 'Is the charger not responding to user inputs or the mobile app interface?   ' +
    (choiceInput || 'N/A') + '\n';
var checkDamage = 'Are there any physical damage or unusual noises during operation?   ' +
    (producer.unusual_noises || 'N/A') + '\n';
var checkErrorMessage = 'What is the error message:   ' + (producer.error_message || 'N/A') + '\n';
var checkUserInformation = 'Caller Contact Information:   ' + (producer.conntact_information || 'N/A');

// Insert short description
var shortDescription = 'Abnormality reported in one of the EV Boxes: ' +
    (producer.cmdb_ci.getDisplayValue() || 'Unknown');

// Insert build incident description
var incidentDecription = 'Issue Description: \n' +
    'The EV Plug electric charger is not functioning correctly. Specific symptoms include: \n' +
    chechCharging + checkError + checkAttempts + checkDispay + checkInput + checkDamage + checkErrorMessage + checkUserInformation;

current.category = 'ev_Box';
current.contact_type = 'self-service';
current.impact = 3;
current.urgency = 3;
current.short_description = shortDescription;
current.description = incidentDecription;
// VoltCare IT Support
current.assignment_group = '597af11b83a71e108eb710c5eeaad3b0';
